<template>
  <div class="article">
    <Nav></Nav>
    <div class="content">
      <el-page-header @back="goBack" content="内容"></el-page-header>
      <div class="c">
        <h3 class="title">{{title}}</h3>
        <p class="date">更新于 {{new Date(date).getFullYear()}}年 {{new Date(date).getMonth() +1}}月 {{new Date(date).getDate()}}日 {{new Date(date).getHours()}}时 {{new Date(date).getMinutes()}}分 {{new Date(date).getSeconds()}}秒</p>
        <el-divider></el-divider>
        <div class="" v-html="html"></div>
      </div>
    </div>
    <bottomFooter></bottomFooter>
  </div>
</template>

<script>
  import Nav from "../../components/Nav";
  import bottomFooter from "../../components/bottomFooter";
  //axios
  import axios from '../../api/index';
  let getArticle = axios.getArticle;//获取文章内容


  export default {
    name: "index",
    components:{
      Nav,
      bottomFooter
    },
    data(){
      return {
        html:'',
        title:'',
        date:''
      }
    },
    methods:{
      goBack() {
        this.$router.push("/blog/0")
      }
    },
    created() {
      document.documentElement.scrollTop = 0;
      getArticle({id:this.$route.params.id})
        .then(data=>{
          if (data.data.code === 0) {
            this.title = data.data.data.title;
            this.date = data.data.data.date;
            this.html = data.data.data.nexContent;
          }else{
            //出错
            this.$router.push("/404");
          }
        })
        .catch(e=>{
          //出错
          this.$router.push("/404");
        })
    }
  }
</script>

<style scoped lang="less">
  .content{
    max-width: 1260px;
    min-width: 1064px;
    min-height:570px;
    margin: 0 auto;
    padding: 100px 10px 15px;
    .c{
      box-sizing: border-box;
      margin-top: 20px;
      padding: 10px 0 0 20px;
      background: rgba(255, 255, 255, 0.77);
      border-radius: 5px;
      font-size: 20px;
      .title{
        margin-bottom: 7px;
      }
      .date{
        font-size: 12px;
        font-weight: bold;
        color: #7f7f7f;
      }
      /deep/.hljs{
        margin: 10px 0;
        background-color: #eee;
      }
      .el-divider{
        background-color: #9d9d9d;
      }
    }
    .el-page-header{
      width: 150px;
      padding: 10px;
      background-color: rgba(255, 255, 255, 0.65);
      border-radius: 20px;
      box-shadow: 0 0 7px #fff;
    }
  }
</style>